\set ON_ERROR_STOP on

BEGIN;
WITH callback_privacy AS (
  DELETE FROM tideway_private.facebook_data_deletion_requests
  WHERE id IN ('73000000-0000-4000-8000-000000000001', '73000000-0000-4000-8000-000000000002', '73000000-0000-4000-8000-000000000003')
  RETURNING privacy_request_id
)
DELETE FROM privacy_requests WHERE id IN (SELECT privacy_request_id FROM callback_privacy WHERE privacy_request_id IS NOT NULL);
DELETE FROM privacy_requests WHERE id IN ('71000000-0000-4000-8000-000000000001', '71000000-0000-4000-8000-000000000003');
DELETE FROM payment_status_history WHERE payment_id = '52000000-0000-4000-8000-000000000001';
DELETE FROM booking_payments WHERE id = '52000000-0000-4000-8000-000000000001';
DELETE FROM bookings WHERE id IN ('40000000-0000-4000-8000-000000000001', '40000000-0000-4000-8000-000000000002', '40000000-0000-4000-8000-000000000003', '40000000-0000-4000-8000-000000000004', '40000000-0000-4000-8000-000000000005');
DELETE FROM cleaning_requests WHERE id IN ('30000000-0000-4000-8000-000000000001', '30000000-0000-4000-8000-000000000002', '30000000-0000-4000-8000-000000000003', '30000000-0000-4000-8000-000000000004');
DELETE FROM properties WHERE id IN ('20000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000002', '20000000-0000-4000-8000-000000000003', '20000000-0000-4000-8000-000000000004');
DELETE FROM cleaner_availability WHERE cleaner_user_id IN ('10000000-0000-4000-8000-000000000001', '10000000-0000-4000-8000-000000000002', '10000000-0000-4000-8000-000000000005');
DELETE FROM cleaner_service_areas WHERE cleaner_user_id IN ('10000000-0000-4000-8000-000000000001', '10000000-0000-4000-8000-000000000002', '10000000-0000-4000-8000-000000000005');
DELETE FROM cleaner_services WHERE cleaner_user_id IN ('10000000-0000-4000-8000-000000000001', '10000000-0000-4000-8000-000000000002', '10000000-0000-4000-8000-000000000005');
DELETE FROM cleaner_profiles WHERE user_id IN ('10000000-0000-4000-8000-000000000001', '10000000-0000-4000-8000-000000000002', '10000000-0000-4000-8000-000000000005');
DELETE FROM landlord_profiles WHERE user_id = '10000000-0000-4000-8000-000000000001';
DELETE FROM audit_logs WHERE actor_user_id IN ('10000000-0000-4000-8000-000000000001', '10000000-0000-4000-8000-000000000002', '10000000-0000-4000-8000-000000000003', '10000000-0000-4000-8000-000000000004', '10000000-0000-4000-8000-000000000005');
DELETE FROM user_roles WHERE user_id IN ('10000000-0000-4000-8000-000000000001', '10000000-0000-4000-8000-000000000002', '10000000-0000-4000-8000-000000000003', '10000000-0000-4000-8000-000000000004', '10000000-0000-4000-8000-000000000005');
DELETE FROM users WHERE id IN ('10000000-0000-4000-8000-000000000001', '10000000-0000-4000-8000-000000000002', '10000000-0000-4000-8000-000000000003', '10000000-0000-4000-8000-000000000004', '10000000-0000-4000-8000-000000000005');
COMMIT;
